import React, { useState, useEffect, useRef } from 'react';
import './NewsAggregator.css';

// Treemap layout algorithm
function treemap(data, width, height) {
  function partition(items, x, y, w, h, direction) {
    if (items.length === 0) return [];
    if (items.length === 1) {
      return [{ ...items[0], x, y, w, h }];
    }

    const totalValue = items.reduce((sum, item) => sum + item.value, 0);
    const ratio = items[0].value / totalValue;

    let result = [];
    if (w > h) {
      // Split vertically
      const w1 = w * ratio;
      result = result.concat(partition(items.slice(0, 1), x, y, w1, h, 'v'));
      result = result.concat(partition(items.slice(1), x + w1, y, w - w1, h, 'h'));
    } else {
      // Split horizontally
      const h1 = h * ratio;
      result = result.concat(partition(items.slice(0, 1), x, y, w, h1, 'h'));
      result = result.concat(partition(items.slice(1), x, y + h1, w, h - h1, 'v'));
    }

    return result;
  }

  return partition(data, 0, 0, width, height, 'h');
}

// Auto-size text to fit container
function autoSizeText(element) {
  const container = element.parentElement;
  if (!container) return;

  const availableWidth = container.clientWidth - 20; // 10px padding each side
  const availableHeight = container.clientHeight - 20;

  let fontSize = 10;
  element.style.fontSize = fontSize + 'px';

  // Grow until overflow
  while (fontSize < 48) {
    element.style.fontSize = fontSize + 'px';
    if (element.scrollWidth > availableWidth || element.scrollHeight > availableHeight) {
      break;
    }
    fontSize++;
  }

  // Shrink back down
  while (fontSize > 10) {
    element.style.fontSize = fontSize + 'px';
    if (element.scrollWidth <= availableWidth && element.scrollHeight <= availableHeight) {
      break;
    }
    fontSize--;
  }
}

const NewsAggregator = ({ articles }) => {
  const [visibleCategories, setVisibleCategories] = useState({
    us: true,
    world: true,
    business: true,
    technology: true,
    entertainment: true,
    sports: true,
    science: true,
    health: true
  });

  const [layout, setLayout] = useState([]);
  const containerRef = useRef(null);

  const categoryColors = {
    us: '#3D5A72',
    world: '#5A7A8C',
    business: '#4A6A4F',
    technology: '#6B5A8A',
    entertainment: '#A85578',
    sports: '#B36844',
    science: '#3A8C89',
    health: '#A84646'
  };

  // Calculate layout
  useEffect(() => {
    if (!containerRef.current) return;

    const width = containerRef.current.clientWidth;
    const height = containerRef.current.clientHeight;

    const visibleArticles = articles.filter(article => visibleCategories[article.category]);
    const data = visibleArticles.map((article, idx) => ({
      id: article.id,
      index: idx,
      value: 1 // Equal size for all cards
    }));

    const newLayout = treemap(data, width, height);
    setLayout(newLayout);
  }, [articles, visibleCategories]);

  // Auto-size text when layout changes
  useEffect(() => {
    document.querySelectorAll('.news-headline').forEach(element => {
      autoSizeText(element);
    });
  }, [layout]);

  const handleCategoryToggle = (category) => {
    setVisibleCategories(prev => ({
      ...prev,
      [category]: !prev[category]
    }));
  };

  const handleCardClick = (link) => {
    if (link) window.open(link, '_blank');
  };

  const visibleArticles = articles.filter(article => visibleCategories[article.category]);

  return (
    <div className="news-aggregator">
      <header className="header">
        <h1>News Aggregator</h1>
        <span className="article-count">{visibleArticles.length} stories</span>
      </header>

      <div className="container" ref={containerRef}>
        {visibleArticles.map((article, idx) => {
          const layoutItem = layout.find(l => l.index === idx);
          if (!layoutItem) return null;

          return (
            <div
              key={article.id}
              className="news-card"
              style={{
                position: 'absolute',
                left: layoutItem.x + 'px',
                top: layoutItem.y + 'px',
                width: layoutItem.w + 'px',
                height: layoutItem.h + 'px',
                backgroundColor: categoryColors[article.category],
                cursor: 'pointer'
              }}
              onClick={() => handleCardClick(article.link)}
            >
              <h2 className="news-headline">{article.title}</h2>
              <div className="news-source">{article.source}</div>
            </div>
          );
        })}
      </div>

      <footer className="footer">
        <div className="category-filters">
          {Object.keys(categoryColors).map(category => (
            <label key={category} className="filter-label">
              <input
                type="checkbox"
                checked={visibleCategories[category]}
                onChange={() => handleCategoryToggle(category)}
                className="filter-checkbox"
              />
              <span>{category.charAt(0).toUpperCase() + category.slice(1)}</span>
            </label>
          ))}
        </div>
      </footer>
    </div>
  );
};

export default NewsAggregator;
